qry:select.qry:xquery:
for $r in sql(' SELECT VIS01_VISITAS_VIS.oi_visita_vis, VIS01_VISITAS.oi_visita, VIS01_VISITAS_VIS.oi_visitante, VIS02_VISITANTES.c_visitante, VIS02_VISITANTES.d_ape_y_nom, VIS01_VISITAS.f_fechahora_ent_es, VIS01_VISITAS_VIS.f_fechahora_sal_es, VIS01_VISITAS.oi_personal_vis, VIS01_VISITAS_VIS.f_fechahora_ent, VIS01_VISITAS_VIS.f_fechahora_sal FROM VIS01_VISITAS, VIS01_VISITAS_VIS, VIS02_VISITANTES JOIN VIS01_VISITAS.oi_visita INNER VIS01_VISITAS_VIS.oi_visita, VIS01_VISITAS_VIS.oi_visitante INNER VIS02_VISITANTES.oi_visitante WHERE (
( VIS01_VISITAS.f_fechahora_ent_es >= {Datetime(#FECHAS:@now_ini)} AND VIS01_VISITAS.f_fechahora_ent_es <= {Datetime(#FECHAS:@now_fin)} ) OR ( VIS01_VISITAS_VIS.f_fechahora_ent < now() AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal) )
) ORDER BY f_fechahora_ent ASC ')/ROWS/ROW

			for $r in sql('
			SELECT VIS01_VISITAS_VIS.oi_visita_vis 
			FROM VIS02_VISITANTES, VIS01_VISITAS_VIS
			JOIN VIS02_VISITANTES.oi_visitante INNER VIS01_VISITAS_VIS.oi_visitante
			WHERE VIS01_VISITAS_VIS.oi_visita = {%=#SOURCE:@oi_visita%}					
			{%? (#SOURCE:@todos ='1') 
				{% AND 1=1  %}
				{% {%? (#SOURCE:@excluir ='1') 
							{% AND VIS02_VISITANTES.oi_visitante not in ({%=string(#SOURCE:VISITANTES/VISITANTE/@id)%}) %}
							{% AND VIS02_VISITANTES.oi_visitante in ({%=string(#SOURCE:VISITANTES/VISITANTE/@id)%}) %}
		  			%}	
		    %}
		  %}
')/ROWS/ROW

for $r in sql(' SELECT VIS01_VISITAS_VIS.oi_visita_vis, VIS01_VISITAS.oi_visita, VIS01_VISITAS_VIS.oi_visitante, VIS02_VISITANTES.c_visitante, VIS02_VISITANTES.d_ape_y_nom, VIS01_VISITAS.f_fechahora_ent_es, VIS01_VISITAS_VIS.f_fechahora_sal_es, VIS01_VISITAS.oi_personal_vis, VIS01_VISITAS_VIS.f_fechahora_ent, VIS01_VISITAS_VIS.f_fechahora_sal FROM VIS01_VISITAS, VIS01_VISITAS_VIS, VIS02_VISITANTES JOIN VIS01_VISITAS.oi_visita INNER VIS01_VISITAS_VIS.oi_visita, VIS01_VISITAS_VIS.oi_visitante INNER VIS02_VISITANTES.oi_visitante WHERE (
( VIS01_VISITAS.f_fechahora_ent_es >= {Datetime(#FECHAS:@now_ini)} AND VIS01_VISITAS.f_fechahora_ent_es <= {Datetime(#FECHAS:@now_fin)} ) OR ( VIS01_VISITAS_VIS.f_fechahora_ent < now() AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal) )
)
{%? (#PARAM:@estado_vis = '1' ) {% AND ( ( ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_ent) AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal) AND VIS01_VISITAS_VIS.f_fechahora_sal_es >= now() ) OR ( ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_ent) AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal) AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal_es) ) ) %} {% %} %}
{%? (#PARAM:@estado_vis = '2' ) {% AND ( ( VIS01_VISITAS.f_fechahora_ent_es >= now() AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_ent) ) OR ( VIS01_VISITAS.f_fechahora_ent_es >= now() AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_ent) AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal) ) ) %} {% %} %}
{%? (#PARAM:@estado_vis = '3' ) {% AND ( ( VIS01_VISITAS.f_fechahora_ent_es <= now() AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal) AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_ent) ) ) %} {% %} %}
{%? (#PARAM:@estado_vis = '4' ) {% AND ( ( ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_sal) ) ) %} {% %} %}
{%? (#PARAM:@estado_vis = '5' ) {% AND ( ( ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_ent) AND VIS01_VISITAS_VIS.f_fechahora_sal_es <= now() AND ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal) ) ) %} {% %} %} ORDER BY f_fechahora_ent ASC ')/ROWS/ROW
